        sum += nums[i]
        val mod = (sum % k + k) % k
        if (prefixSum.containsKey(mod)) {
            val prevIndex = prefixSum[mod]!!
            if (prevIndex == -1L) {
                dp[i + 1] = 0L
            } else {
                dp[i + 1] = dp[prevIndex.toInt() + 1]
            }
        } else {
            dp[i + 1] = dp[i] + nums[i]
        }
        prefixSum[mod] = i.toLong()
    }

    return dp[n]
}
